-- calc_loops_name
-- Field: Loops.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_loops_name(p_loop_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(loop_id, '') FROM loops WHERE loop_id = p_loop_id))::text;
$$ LANGUAGE sql STABLE;

