-- calc_studies_total_cases
-- Field: Studies.TotalCases
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_studies_total_cases(p_study_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((cases)::numeric), 0) FROM case_cells WHERE study = p_study_id))::integer;
$$ LANGUAGE sql STABLE;

