$$ LANGUAGE sql STABLE;

-- calc_treatments_total_successes
-- Field: Treatments.TotalSuccesses
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_treatments_total_successes(p_treatment_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((successes)::numeric), 0) FROM case_cells WHERE study = (SELECT NULLIF(study, '') FROM treatments WHERE treatment_id = p_treatment_id) AND treatment_label = (SELECT NULLIF(treatment_label, '') FROM treatments WHERE treatment_id = p_treatment_id)))::integer;
